/* Center anything horizontally and vertically */
.center-everything {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
}

/* Space items evenly in a navbar */
.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 1rem 2rem;
  gap: 1rem;
}

/* Responsive card row that wraps */
.card-row {
  display: flex;
  flex-wrap: wrap;
  gap: 1.5rem;
}

.card-row > .card {
  flex: 1 1 280px; /* grow, shrink, min-width */
}

/* Basic 2-column layout: sidebar + main content */
.page-layout {
  display: grid;
  grid-template-columns: 250px 1fr; /* fixed sidebar, fluid content */
  grid-template-rows: auto 1fr auto; /* header, content, footer */
  gap: 1.5rem;
  min-height: 100vh;
}

/* Make it single-column on small screens */
@media (max-width: 768px) {
  .page-layout {
    grid-template-columns: 1fr;
  }
}

/* Equal-width card grid that auto-fills */
.auto-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1.5rem;
}

/* Flexbox: one-dimensional (row OR column) */
.flex-nav {
  display: flex;
  gap: 1rem;
  align-items: center;
}

.flex-nav .logo { margin-right: auto; } /* Push everything else right */

/* Grid: two-dimensional (rows AND columns) */
.grid-layout {
  display: grid;
  grid-template-columns: 200px 1fr;
  grid-template-rows: auto 1fr auto;
  gap: 1rem;
  min-height: 100vh;
}

// --- Variables ---
const API_URL = 'https://api.example.com'; // constant, cannot be reassigned
let count = 0;                             // can be reassigned
// var is legacy -- always prefer const, then let

// --- Regular function ---
function greet(name) {
  return `Hello, ${name}!`;
}

// --- Arrow function (shorter syntax) ---
const greetArrow = (name) => `Hello, ${name}!`;

// --- Arrow function with body ---
const calculateTax = (price, rate = 0.1) => {
  const tax = price * rate;
  return price + tax;
};

// --- Destructuring ---
const user = { name: 'Alice', age: 28, role: 'developer' };
const { name, role } = user; // name = 'Alice', role = 'developer'

const colors = ['red', 'green', 'blue'];
const [first, second] = colors; // first = 'red', second = 'green'

// --- Spread operator ---
const newColors = [...colors, 'purple']; // ['red', 'green', 'blue', 'purple']
const updatedUser = { ...user, age: 29 }; // shallow copy with age overridden

// --- Optional chaining ---
const city = user?.address?.city ?? 'Unknown'; // safe deep access

// Fetch data from an API using async/await
async function getUsers() {
  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/users');

    if (!response.ok) {
      throw new Error(`HTTP error! Status: ${response.status}`);
    }

    const users = await response.json();
    console.log(users);
    return users;
  } catch (error) {
    console.error('Failed to fetch users:', error.message);
    return [];
  }
}

// POST data to an API
async function createUser(userData) {
  try {
    const response = await fetch('https://jsonplaceholder.typicode.com/users', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(userData),
    });

    if (!response.ok) throw new Error(`HTTP ${response.status}`);
    return await response.json();
  } catch (error) {
    console.error('Failed to create user:', error.message);
    throw error; // re-throw so the caller can handle it
  }
}

const products = [
  { id: 1, name: 'Laptop', price: 999, inStock: true },
  { id: 2, name: 'Phone', price: 699, inStock: false },
  { id: 3, name: 'Tablet', price: 449, inStock: true },
  { id: 4, name: 'Watch', price: 299, inStock: true },
];

// map -- transform every item into something new
const names = products.map(p => p.name);
// ['Laptop', 'Phone', 'Tablet', 'Watch']

// filter -- keep only items that pass a test
const available = products.filter(p => p.inStock);
// [{ id: 1, ... }, { id: 3, ... }, { id: 4, ... }]

// find -- get the first item that matches
const phone = products.find(p => p.name === 'Phone');
// { id: 2, name: 'Phone', price: 699, inStock: false }

// Chaining: get names of available products under $500
const deals = products
  .filter(p => p.inStock && p.price < 500)
  .map(p => p.name);
// ['Tablet', 'Watch']

// reduce -- accumulate a single value from an array
const total = products.reduce((sum, p) => sum + p.price, 0);
// 2446

// some / every -- boolean checks
const anyInStock = products.some(p => p.inStock);   // true
const allInStock = products.every(p => p.inStock);  // false

