// Callbacks for async
function getUser(id, callback) {
  var xhr = new XMLHttpRequest();
  xhr.open('GET', '/api/users/' + id);
  xhr.onload = function() {
    if (xhr.status === 200) {
      callback(null, JSON.parse(xhr.responseText));
    } else {
      callback(new Error('Request failed'));
    }
  };
  xhr.send();
}

